import {
  isDryRun,
  makeRunner,
  parseAndValidateCreateFuturesGridBuOrderData,
  parseAndValidateCreateSpotGridBuOrderData,
  parseJsonFlag,
  print,
  toToolErrorPayload,
  version
} from "./chunk-I6Z3QX5T.js";

// src/trade.ts
import { Command as Command8 } from "commander";

// src/completion.ts
import { createRequire } from "module";
var _require = createRequire(import.meta.url);
var COMPLETION_TREE = {
  groups: ["market", "account", "wallet", "orders", "bot", "earn", "capabilities"],
  market: ["depth", "trades", "symbols", "tickers", "book_tickers", "klines"],
  account: ["balance"],
  wallet: ["balance_full"],
  orders: ["new", "get", "open", "all", "fills", "fills_by_order_id", "cancel", "cancel_all"],
  bot: ["order_list", "futures_grid", "spot_grid", "smart_copy", "signal"],
  futures_grid: ["get", "create", "adjust_params", "reduce", "cancel", "check_params"],
  spot_grid: ["get", "get_ai_strategy", "create", "adjust_params", "invest_in", "cancel", "profit", "check_params"],
  smart_copy: ["get", "create", "cancel", "check_params"],
  signal: ["listener"],
  earn: ["dual"],
  dual: [
    "symbols",
    "open_products",
    "prices",
    "index",
    "delivery_prices",
    "balances",
    "get_invests",
    "records",
    "invest",
    "revoke_invest",
    "collect"
  ]
};
function initCompletion() {
  const omelette = _require("omelette");
  const completion2 = omelette("pionex-trade-cli <group> <sub> <cmd>");
  const T = COMPLETION_TREE;
  completion2.on("group", ({ reply }) => reply(T.groups));
  completion2.on("market", ({ reply }) => reply(T.market));
  completion2.on("account", ({ reply }) => reply(T.account));
  completion2.on("wallet", ({ reply }) => reply(T.wallet));
  completion2.on("orders", ({ reply }) => reply(T.orders));
  completion2.on("bot", ({ reply }) => reply(T.bot));
  completion2.on("futures_grid", ({ reply }) => reply(T.futures_grid));
  completion2.on("spot_grid", ({ reply }) => reply(T.spot_grid));
  completion2.on("smart_copy", ({ reply }) => reply(T.smart_copy));
  completion2.on("signal", ({ reply }) => reply(T.signal));
  completion2.on("earn", ({ reply }) => reply(T.earn));
  completion2.on("dual", ({ reply }) => reply(T.dual));
  completion2.init();
  return completion2;
}
function generateFishCompletion() {
  const cmd = "pionex-trade-cli";
  const T = COMPLETION_TREE;
  const lines = [
    `# ${cmd} fish shell completion`,
    `# Generated by: ${cmd} setup-completion-fish`,
    `# To install:   ${cmd} setup-completion-fish > ~/.config/fish/completions/${cmd}.fish`,
    "",
    "# Disable file completion globally for this command",
    `complete -c ${cmd} -f`,
    "",
    "# Top-level groups",
    ...T.groups.map(
      (g) => `complete -c ${cmd} -n 'not __fish_seen_subcommand_from ${T.groups.join(" ")}' -a '${g}'`
    ),
    "",
    "# market subcommands",
    ...T.market.map((s) => `complete -c ${cmd} -n '__fish_seen_subcommand_from market' -a '${s}'`),
    "",
    "# account subcommands",
    ...T.account.map((s) => `complete -c ${cmd} -n '__fish_seen_subcommand_from account' -a '${s}'`),
    "",
    "# wallet subcommands",
    ...T.wallet.map((s) => `complete -c ${cmd} -n '__fish_seen_subcommand_from wallet' -a '${s}'`),
    "",
    "# orders subcommands",
    ...T.orders.map((s) => `complete -c ${cmd} -n '__fish_seen_subcommand_from orders' -a '${s}'`),
    "",
    "# bot subcommands (only before entering futures_grid, spot_grid, smart_copy, or signal)",
    ...T.bot.map((s) => `complete -c ${cmd} -n '__fish_seen_subcommand_from bot; and not __fish_seen_subcommand_from futures_grid spot_grid smart_copy signal' -a '${s}'`),
    "",
    "# bot futures_grid commands",
    ...T.futures_grid.map((s) => `complete -c ${cmd} -n '__fish_seen_subcommand_from futures_grid' -a '${s}'`),
    "",
    "# bot spot_grid commands",
    ...T.spot_grid.map((s) => `complete -c ${cmd} -n '__fish_seen_subcommand_from spot_grid' -a '${s}'`),
    "",
    "# bot smart_copy commands",
    ...T.smart_copy.map((s) => `complete -c ${cmd} -n '__fish_seen_subcommand_from smart_copy' -a '${s}'`),
    "",
    "# bot signal commands",
    ...T.signal.map((s) => `complete -c ${cmd} -n '__fish_seen_subcommand_from signal' -a '${s}'`),
    "",
    "# earn subcommands (only before entering dual)",
    ...T.earn.map((s) => `complete -c ${cmd} -n '__fish_seen_subcommand_from earn; and not __fish_seen_subcommand_from dual' -a '${s}'`),
    "",
    "# earn dual commands",
    ...T.dual.map((s) => `complete -c ${cmd} -n '__fish_seen_subcommand_from dual' -a '${s}'`),
    ""
  ];
  return lines.join("\n");
}

// src/commands/market.ts
import { Command } from "commander";
function buildMarketCommand() {
  const market = new Command("market").description("Market data (public, no auth required)");
  market.command("depth <symbol>").description("Get order book depth for a symbol").option("--limit <n>", "Number of price levels to return", parseInt).action(async (symbol, opts, cmd) => {
    try {
      const run = makeRunner(cmd);
      const out = await run("pionex_market_get_depth", { symbol, limit: opts.limit });
      print(out.data);
    } catch (e) {
      process.stderr.write(JSON.stringify(toToolErrorPayload(e), null, 2) + "\n");
      process.exit(1);
    }
  });
  market.command("trades <symbol>").description("Get recent trades for a symbol").option("--limit <n>", "Number of trades to return", parseInt).action(async (symbol, opts, cmd) => {
    try {
      const run = makeRunner(cmd);
      const out = await run("pionex_market_get_trades", { symbol, limit: opts.limit });
      print(out.data);
    } catch (e) {
      process.stderr.write(JSON.stringify(toToolErrorPayload(e), null, 2) + "\n");
      process.exit(1);
    }
  });
  market.command("symbols").description("Get symbol/trading pair information").option("--symbols <list>", "Comma-separated symbol list (e.g. BTC_USDT)").option("--type <type>", "Symbol type filter").action(async (opts, cmd) => {
    try {
      const run = makeRunner(cmd);
      const out = await run("pionex_market_get_symbol_info", { symbols: opts.symbols, type: opts.type });
      print(out.data);
    } catch (e) {
      process.stderr.write(JSON.stringify(toToolErrorPayload(e), null, 2) + "\n");
      process.exit(1);
    }
  });
  market.command("tickers").description("Get 24h ticker statistics").option("--symbol <symbol>", "Filter by symbol (e.g. BTC_USDT)").option("--type <type>", "Symbol type filter").action(async (opts, cmd) => {
    try {
      const run = makeRunner(cmd);
      const out = await run("pionex_market_get_tickers", { symbol: opts.symbol, type: opts.type });
      print(out.data);
    } catch (e) {
      process.stderr.write(JSON.stringify(toToolErrorPayload(e), null, 2) + "\n");
      process.exit(1);
    }
  });
  market.command("book_tickers").description("Get best bid/ask prices for symbols").option("--symbol <symbol>", "Filter by symbol (e.g. BTC_USDT)").option("--type <type>", "Symbol type filter").action(async (opts, cmd) => {
    try {
      const run = makeRunner(cmd);
      const out = await run("pionex_market_get_book_tickers", { symbol: opts.symbol, type: opts.type });
      print(out.data);
    } catch (e) {
      process.stderr.write(JSON.stringify(toToolErrorPayload(e), null, 2) + "\n");
      process.exit(1);
    }
  });
  market.command("klines [symbol] [interval]").description("Get candlestick/kline data\n  Valid intervals: 1M 5M 15M 30M 60M 4H 8H 12H 1D\n  Example: pionex-trade-cli market klines BTC_USDT 60M").option("--symbol <symbol>", "Trading pair (e.g. BTC_USDT)").option("--interval <interval>", "Kline interval: 1M 5M 15M 30M 60M 4H 8H 12H 1D").option("--end-time <ms>", "End time in milliseconds", parseInt).option("--limit <n>", "Number of klines to return", parseInt).action(async (posSymbol, posInterval, opts, cmd) => {
    try {
      const symbol = opts.symbol ?? posSymbol;
      const interval = opts.interval ?? posInterval;
      if (!symbol || !interval) {
        throw new Error("Missing symbol/interval. Example: pionex-trade-cli market klines BTC_USDT 60M");
      }
      const run = makeRunner(cmd);
      const out = await run("pionex_market_get_klines", { symbol, interval, endTime: opts.endTime, limit: opts.limit });
      print(out.data);
    } catch (e) {
      process.stderr.write(JSON.stringify(toToolErrorPayload(e), null, 2) + "\n");
      process.exit(1);
    }
  });
  return market;
}

